using System.Text;using Asp.Versioning;using Fixar.API.Security;using Fixar.Application.Common.Models;using Fixar.Domain.Entities;using Fixar.Infrastructure.Identity;using Fixar.Infrastructure.Persistence;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;
namespace Fixar.API.Controllers;
[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/financial-transactions"),Authorize(Policy=AuthorizationPolicies.CanViewFinancialAccounts)]
public class FinancialTransactionsController(ApplicationDbContext db):ControllerBase
{
 [HttpGet]public async Task<IActionResult>List(Guid? accountId,string? direction,string? transactionType,string? sourceType,string? currency,DateTime? dateFrom,DateTime? dateTo,string? search,CancellationToken ct){var q=db.FinancialTransactions.AsNoTracking().AsQueryable();if(accountId.HasValue)q=q.Where(x=>x.FinancialAccountId==accountId);if(!string.IsNullOrWhiteSpace(direction))q=q.Where(x=>x.Direction==direction);if(!string.IsNullOrWhiteSpace(transactionType))q=q.Where(x=>x.TransactionType==transactionType);if(!string.IsNullOrWhiteSpace(sourceType))q=q.Where(x=>x.SourceType==sourceType);if(!string.IsNullOrWhiteSpace(currency))q=q.Where(x=>x.Currency==currency.ToUpper());if(dateFrom.HasValue)q=q.Where(x=>x.TransactionDate>=dateFrom);if(dateTo.HasValue)q=q.Where(x=>x.TransactionDate<=dateTo);if(!string.IsNullOrWhiteSpace(search)){var s=search.ToLower();q=q.Where(x=>x.TransactionNumber.ToLower().Contains(s)||(x.ReferenceNumber!=null&&x.ReferenceNumber.ToLower().Contains(s))||(x.Description!=null&&x.Description.ToLower().Contains(s)));}var rows=await q.OrderByDescending(x=>x.TransactionDate).Select(x=>new FinancialTransactionListDto(x.Id,x.TransactionNumber,x.FinancialAccountId,x.FinancialAccount.AccountCode,x.FinancialAccount.Name,x.TransactionDate,x.ValueDate,x.TransactionType,x.Direction,x.SourceType,x.CustomerId,x.Currency,x.Amount,x.Description,x.ReferenceNumber,x.IsReversed)).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(rows));}
 [HttpGet("{id:guid}")]public async Task<IActionResult>Detail(Guid id,CancellationToken ct){var x=await db.FinancialTransactions.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.TransactionNumber,x.FinancialAccountId,Account=x.FinancialAccount.Name,x.TransactionDate,x.ValueDate,x.TransactionType,x.Direction,x.SourceType,x.SourceId,x.CustomerId,x.CustomerCollectionId,x.ChequeId,x.Currency,x.Amount,x.Description,x.ReferenceNumber,x.BankReference,x.IsReversed,x.ReversalTransactionId,x.ReversedAt,x.ReversedBy,x.ReversalReason}).FirstOrDefaultAsync(ct);return x is null?NotFound():Ok(ApiResponse<object>.SuccessResponse(x));}
 [HttpPost("manual-income"),Authorize(Policy=AuthorizationPolicies.CanRecordFinancialTransactions),Idempotent]public Task<IActionResult>Income(ManualTransactionRequest r,CancellationToken ct)=>Manual(r,"Inflow","ManualIncome",ct);
 [HttpPost("manual-expense"),Authorize(Policy=AuthorizationPolicies.CanRecordFinancialTransactions),Idempotent]public Task<IActionResult>Expense(ManualTransactionRequest r,CancellationToken ct)=>Manual(r,"Outflow","ManualExpense",ct);
 [HttpPost("transfer"),Authorize(Policy=AuthorizationPolicies.CanRecordFinancialTransactions),Idempotent]public async Task<IActionResult>Transfer(TransferRequest r,CancellationToken ct){if(r.Amount<=0)return BadRequest(ApiResponse<object>.Fail("Tutar sıfırdan büyük olmalıdır.","VALIDATION_ERROR"));if(r.SourceAccountId==r.TargetAccountId)return BadRequest(ApiResponse<object>.Fail("Hesaplar arası transferde kaynak ve hedef aynı olamaz.","SAME_ACCOUNT"));await using var tx=await db.Database.BeginTransactionAsync(ct);var accounts=await db.FinancialAccounts.Where(x=>x.Id==r.SourceAccountId||x.Id==r.TargetAccountId).ToListAsync(ct);var source=accounts.FirstOrDefault(x=>x.Id==r.SourceAccountId);var target=accounts.FirstOrDefault(x=>x.Id==r.TargetAccountId);if(source is null||target is null)return NotFound(ApiResponse<object>.Fail("Finans hesabı bulunamadı.","ACCOUNT_NOT_FOUND"));if(!source.IsActive||!target.IsActive)return Conflict(ApiResponse<object>.Fail("Finans hesabı aktif değil.","ACCOUNT_INACTIVE"));if(source.Currency!=target.Currency)return Conflict(ApiResponse<object>.Fail("Farklı para birimleri arasında transfer desteklenmiyor.","CURRENCY_MISMATCH"));var reference=string.IsNullOrWhiteSpace(r.ReferenceNumber)?$"TRF-{Guid.NewGuid():N}":r.ReferenceNumber;var sourceTx=await Create(source,"Outflow","AccountTransfer","AccountTransfer",null,null,r.Amount,r.TransactionDate,r.Description,reference,ct);var targetTx=await Create(target,"Inflow","AccountTransfer","AccountTransfer",sourceTx.Id,null,r.Amount,r.TransactionDate,r.Description,reference,ct);sourceTx.SourceId=targetTx.Id;CustomerFinanceSupport.Audit(db,this,"Account Transfer Created",sourceTx.Id,new{r.SourceAccountId,r.TargetAccountId,r.Amount,source.Currency,reference});await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{reference,SourceTransactionId=sourceTx.Id,TargetTransactionId=targetTx.Id}));}
 [HttpPost("{id:guid}/reverse"),Authorize(Policy=AuthorizationPolicies.CanReverseFinancialTransactions),Idempotent]public async Task<IActionResult>Reverse(Guid id,ReverseFinancialRequest r,CancellationToken ct){if(string.IsNullOrWhiteSpace(r.Reason))return BadRequest(ApiResponse<object>.Fail("Geri alma gerekçesi zorunludur.","VALIDATION_ERROR"));await using var tx=await db.Database.BeginTransactionAsync(ct);var original=await db.FinancialTransactions.Include(x=>x.FinancialAccount).FirstOrDefaultAsync(x=>x.Id==id,ct);if(original is null)return NotFound();if(original.IsReversed)return Conflict(ApiResponse<object>.Fail("Bu finansal hareket daha önce geri alınmış.","ALREADY_REVERSED"));var reverse=await Create(original.FinancialAccount,original.Direction=="Inflow"?"Outflow":"Inflow","Reversal","Reversal",original.Id,original.CustomerId,original.Amount,DateTime.UtcNow,r.Reason,original.ReferenceNumber,ct);original.IsReversed=true;original.ReversedAt=DateTime.UtcNow;original.ReversedBy=User.Identity?.Name;original.ReversalReason=r.Reason;original.ReversalTransactionId=reverse.Id;CustomerFinanceSupport.Audit(db,this,"Financial Transaction Reversed",original.Id,r);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{original.Id,ReversalTransactionId=reverse.Id}));}
 [HttpGet("summary")]public async Task<IActionResult>Summary(CancellationToken ct){var today=DateTime.UtcNow.Date;var month=new DateTime(today.Year,today.Month,1,0,0,0,DateTimeKind.Utc);var rows=await db.FinancialTransactions.AsNoTracking().Where(x=>!x.IsReversed).GroupBy(x=>x.Currency).Select(g=>new{Currency=g.Key,TodayIn=g.Where(x=>x.TransactionDate>=today&&x.Direction=="Inflow").Sum(x=>(decimal?)x.Amount)??0,TodayOut=g.Where(x=>x.TransactionDate>=today&&x.Direction=="Outflow").Sum(x=>(decimal?)x.Amount)??0,MonthIn=g.Where(x=>x.TransactionDate>=month&&x.Direction=="Inflow").Sum(x=>(decimal?)x.Amount)??0,MonthOut=g.Where(x=>x.TransactionDate>=month&&x.Direction=="Outflow").Sum(x=>(decimal?)x.Amount)??0}).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(rows));}
 [HttpGet("collection-backfill-preview")]public async Task<IActionResult>CollectionBackfillPreview(CancellationToken ct){var q=db.CustomerCollections.AsNoTracking();var methods=await q.GroupBy(x=>x.PaymentMethod).Select(g=>new{PaymentMethod=g.Key,Count=g.Count()}).ToListAsync(ct);var candidates=await q.Where(x=>x.Status!="Draft"&&x.Status!="Cancelled"&&!x.IsReversed&&!x.FinancialTransactionId.HasValue&&!x.CustomerChequeId.HasValue).Select(x=>new{x.Id,x.CollectionNumber,x.CustomerId,x.CollectionDate,x.PaymentMethod,x.Currency,x.Amount,Warning=x.PaymentMethod=="Cheque"?"Çek bilgileri ve açık finans kararı gereklidir.":"Finans hesabı açıkça seçilmelidir."}).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{Total=await q.CountAsync(ct),Draft=await q.CountAsync(x=>x.Status=="Draft",ct),Posted=await q.CountAsync(x=>x.Status!="Draft"&&x.Status!="Cancelled",ct),PaymentMethods=methods,WithoutFinancialPosting=candidates.Count,Candidates=candidates}));}
 [HttpGet("cash-flow"),Authorize(Policy=AuthorizationPolicies.CanViewCashFlow)]public async Task<IActionResult>CashFlow(DateTime? dateFrom,DateTime? dateTo,string? currency,CancellationToken ct){var from=(dateFrom??DateTime.UtcNow.Date.AddDays(-30)).Date;var to=(dateTo??DateTime.UtcNow).Date.AddDays(1);var q=db.FinancialTransactions.AsNoTracking().Where(x=>!x.IsReversed&&x.TransactionDate>=from&&x.TransactionDate<to);if(!string.IsNullOrWhiteSpace(currency))q=q.Where(x=>x.Currency==currency.ToUpper());var raw=await q.Select(x=>new{x.TransactionDate,x.Currency,x.Direction,x.TransactionType,x.SourceType,x.Amount}).ToListAsync(ct);var rows=raw.GroupBy(x=>new{x.TransactionDate.Date,x.Currency}).Select(g=>new{Date=g.Key.Date,g.Key.Currency,Inflow=g.Where(x=>x.Direction=="Inflow").Sum(x=>x.Amount),Outflow=g.Where(x=>x.Direction=="Outflow").Sum(x=>x.Amount),NetCashFlow=g.Where(x=>x.TransactionType!="AccountTransfer").Sum(x=>x.Direction=="Inflow"?x.Amount:-x.Amount),TransferIn=g.Where(x=>x.TransactionType=="AccountTransfer"&&x.Direction=="Inflow").Sum(x=>x.Amount),TransferOut=g.Where(x=>x.TransactionType=="AccountTransfer"&&x.Direction=="Outflow").Sum(x=>x.Amount),TransactionCount=g.Count()}).OrderBy(x=>x.Date).ToList();return Ok(ApiResponse<object>.SuccessResponse(rows));}
 [HttpGet("export.csv"),Authorize(Policy=AuthorizationPolicies.CanViewCashFlow)]public async Task<IActionResult>Export(CancellationToken ct){var rows=await db.FinancialTransactions.AsNoTracking().OrderByDescending(x=>x.TransactionDate).Select(x=>new{x.TransactionNumber,x.TransactionDate,Account=x.FinancialAccount.Name,x.Direction,x.TransactionType,x.SourceType,x.ReferenceNumber,x.Amount,x.Currency,x.IsReversed}).ToListAsync(ct);var sb=new StringBuilder("\uFEFFİşlem No;Tarih;Hesap;Yön;Tür;Kaynak;Referans;Tutar;Para Birimi;Geri Alındı\n");foreach(var x in rows)sb.AppendLine($"{x.TransactionNumber};{x.TransactionDate:dd.MM.yyyy};{x.Account};{x.Direction};{x.TransactionType};{x.SourceType};{x.ReferenceNumber};{x.Amount};{x.Currency};{x.IsReversed}");CustomerFinanceSupport.Audit(db,this,"Cash Flow Exported",Guid.Empty,new{});await db.SaveChangesAsync(ct);return File(Encoding.UTF8.GetBytes(sb.ToString()),"text/csv; charset=utf-8","finansal-hareketler.csv");}
 async Task<IActionResult>Manual(ManualTransactionRequest r,string direction,string type,CancellationToken ct){if(r.Amount<=0)return BadRequest(ApiResponse<object>.Fail("Tutar sıfırdan büyük olmalıdır.","VALIDATION_ERROR"));await using var tx=await db.Database.BeginTransactionAsync(ct);var account=await db.FinancialAccounts.FirstOrDefaultAsync(x=>x.Id==r.FinancialAccountId,ct);if(account is null)return NotFound(ApiResponse<object>.Fail("Finans hesabı bulunamadı.","ACCOUNT_NOT_FOUND"));if(!account.IsActive)return Conflict(ApiResponse<object>.Fail("Finans hesabı aktif değil.","ACCOUNT_INACTIVE"));var x=await Create(account,direction,type,"Manual",Guid.NewGuid(),r.CustomerId,r.Amount,r.TransactionDate,r.Description,r.ReferenceNumber,ct);CustomerFinanceSupport.Audit(db,this,"Financial Transaction Created",x.Id,r);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.TransactionNumber}));}
 async Task<FinancialTransaction>Create(FinancialAccount account,string direction,string type,string sourceType,Guid? sourceId,Guid? customerId,decimal amount,DateTime date,string? description,string? reference,CancellationToken ct){await db.Database.ExecuteSqlRawAsync("SELECT pg_advisory_xact_lock(81311)",ct);var prefix=$"FTX-{date:yyyyMMdd}-";var values=await db.FinancialTransactions.Where(x=>x.TransactionNumber.StartsWith(prefix)).Select(x=>x.TransactionNumber).ToListAsync(ct);var next=values.Select(x=>int.TryParse(x[prefix.Length..],out var n)?n:0).DefaultIfEmpty().Max()+1;var x=new FinancialTransaction{Id=Guid.NewGuid(),TransactionNumber=$"{prefix}{next:0000}",FinancialAccountId=account.Id,FinancialAccount=account,TransactionDate=date.ToUniversalTime(),TransactionType=type,Direction=direction,SourceType=sourceType,SourceId=sourceId,CustomerId=customerId,Currency=account.Currency,Amount=amount,Description=description,ReferenceNumber=reference,Created=DateTime.UtcNow};db.FinancialTransactions.Add(x);return x;}
}
public record FinancialTransactionListDto(Guid Id,string TransactionNumber,Guid FinancialAccountId,string AccountCode,string AccountName,DateTime TransactionDate,DateTime? ValueDate,string TransactionType,string Direction,string SourceType,Guid? CustomerId,string Currency,decimal Amount,string? Description,string? ReferenceNumber,bool IsReversed);
public record ManualTransactionRequest(Guid FinancialAccountId,DateTime TransactionDate,decimal Amount,Guid? CustomerId,string? Description,string? ReferenceNumber);
public record TransferRequest(Guid SourceAccountId,Guid TargetAccountId,DateTime TransactionDate,decimal Amount,string? Description,string? ReferenceNumber);
public record ReverseFinancialRequest(string Reason);
